+    {
+        coalescer_requeue_requests(rq, batch);
+        restored_any = true;
+    }
+    if let Some(work) = pending_spilled.take() {
+        coalescer_restore_spilled_work(rq, work);
+        restored_any = true;
+    }
+    if let Some(work) = inflight_spilled.take() {
+        coalescer_restore_spilled_work(rq, work);
+        restored_any = true;
+    }
+    restored_any
+}
